import {
  ChangeDetectorRef,
  Component,
  ElementRef,
  inject,
  ViewChild,
  input,
  output,
  effect,
  OnDestroy,
} from '@angular/core';
import { ButtonModule } from 'primeng/button';
import { DialogModule } from 'primeng/dialog';
import { FileSelectEvent, FileUploadModule } from 'primeng/fileupload';
import { StepsModule } from 'primeng/steps';
import { ImageModule } from 'primeng/image';
import {
  ImageCroppedEvent,
  ImageCropperComponent,
  ImageTransform,
} from 'ngx-image-cropper';
import { ToggleSwitchModule } from 'primeng/toggleswitch';
import { FormsModule } from '@angular/forms';
import { SliderModule } from 'primeng/slider';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { MessageModule } from 'primeng/message';
import { TooltipModule } from 'primeng/tooltip';
import {
  hasProperty,
  isDefined,
  isNullOrUndefined,
  isString,
} from '../../utils';
import { TranslatePipe } from '@ngx-translate/core';

@Component({
  selector: 'app-image-editor',
  imports: [
    FormsModule,
    FileUploadModule,
    DialogModule,
    ImageModule,
    ButtonModule,
    StepsModule,
    ToggleSwitchModule,
    ImageCropperComponent,
    SliderModule,
    ProgressSpinnerModule,
    MessageModule,
    TooltipModule,
    TranslatePipe,
  ],
  templateUrl: './image-editor.component.html',
  styleUrl: './image-editor.component.scss',
})
export class ImageEditorComponent implements OnDestroy {
  @ViewChild('cropper') cropper!: ImageCropperComponent;
  @ViewChild('originalImage') originalImage!: ElementRef<HTMLImageElement>;
  @ViewChild('canvas') canvas!: ElementRef<HTMLCanvasElement>;
  @ViewChild('fileInput') fileInput!: ElementRef<HTMLInputElement>;

  readonly visible = input(true);
  readonly aspectRatio = input(1);
  readonly maxWidth = input(1920);
  readonly maxHeight = input(1080);
  readonly paddingPercentage = input(0.1);
  readonly backgroundColor = input('white');
  readonly saveOnEmpty = input(false);
  readonly fileUrl = input<string | undefined | null>(null);

  readonly visibleChange = output<boolean>();
  readonly croppedFile = output<File>();
  readonly fileSelected = output<File>();
  readonly uploadError = output<string>();
  readonly imageCropped = output<ImageCroppedEvent>();
  readonly imageLoaded = output<void>();
  readonly imageRemoved = output<void>();
  readonly loadError = output<string>();

  private readonly cdr = inject(ChangeDetectorRef);

  currentFile: File | null = null;
  croppedImageUrl: string | null = null;
  canvasRotation = 0;
  isImageRemoved = false;
  transform: ImageTransform = {
    scale: 1,
  };

  isLoading = false;
  errorMessage: string | null = null;
  cropperReady = false;

  constructor() {
    effect(() => {
      const fileUrl = this.fileUrl();
      if (isDefined(fileUrl)) {
        this.loadImageFromUrl(fileUrl);
      } else {
        this.isImageRemoved = true;
      }
    });
  }

  /**
   * Handles file selection event.
   * @param event The file selection event.
   */
  onFileSelect(event: FileSelectEvent): void {
    this.errorMessage = null;
    this.cropperReady = false;
    const file = event.files[0];
    if (isDefined(file)) {
      this.fileSelected.emit(file);
      this.processOriginal(file);
    }
  }

  /**
   * Loads an image from a URL.
   * @param url The URL of the image.
   */
  loadImageFromUrl(url: string): void {
    if (isNullOrUndefined(url)) {
      this.isLoading = true;
      return;
    }
    this.errorMessage = null;
    this.isImageRemoved = false;
    const img = new Image();
    img.crossOrigin = 'Anonymous';
    img.onload = () => {
      this.originalImage.nativeElement.src = url;
      this.processOriginalFromElement(img);
      this.isLoading = true;
    };
    img.onerror = () => {
      this.isLoading = false;
      this.isImageRemoved = true;
      this.errorMessage =
        'Error loading image from URL. Please try another URL.';
      this.loadError.emit(this.errorMessage);
    };
    img.src = url;
  }

  /**
   * Processes the original image file.
   * @param file The original image file.
   */
  processOriginal(file: File): void {
    const reader = new FileReader();
    reader.onload = (e: ProgressEvent<FileReader>) => {
      if (!isDefined(e.target) || !hasProperty(e.target, 'result')) {
        this.handleError('Error reading file');
        return;
      }

      const result = e.target.result;
      if (!isString(result)) {
        this.handleError('Invalid file format');
        return;
      }

      // Use originalImage ViewChild if available, otherwise create a temporary image element
      let imgElement: HTMLImageElement;

      if (isDefined(this.originalImage?.nativeElement)) {
        imgElement = this.originalImage.nativeElement;
        imgElement.src = result;
      } else {
        // Create temporary image element for processing
        imgElement = new Image();
        imgElement.src = result;
      }

      imgElement.onload = () => {
        this.processOriginalFromElement(imgElement);
      };

      imgElement.onerror = () => {
        this.handleError('Error loading image');
      };
    };

    reader.onerror = () => {
      this.handleError('Error reading file');
    };

    reader.readAsDataURL(file);
  }

  private handleError(message: string): void {
    this.errorMessage = message;
    this.loadError.emit(message);
    this.isLoading = false;
  }

  /**
   * Processes the original image element.
   * @param img The original image element.
   */
  processOriginalFromElement(img: HTMLImageElement): void {
    const src = img;

    // Use canvas ViewChild if available, otherwise create a temporary canvas
    let dst: HTMLCanvasElement;

    if (isDefined(this.canvas?.nativeElement)) {
      dst = this.canvas.nativeElement;
    } else {
      // Create temporary canvas element for processing
      dst = document.createElement('canvas');
    }

    const xpadding = (src.width / 2) * this.paddingPercentage();
    const ypadding = (src.height / 2) * this.paddingPercentage();

    dst.width = src.width + xpadding * 2;
    dst.height = src.height + ypadding * 2;

    const ctx = dst.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.rect(0, 0, dst.width, dst.height);
      ctx.fillStyle = this.backgroundColor();
      ctx.fill();
      ctx.drawImage(src, xpadding, ypadding, src.width, src.height);

      dst.toBlob((blob) => {
        if (blob) {
          const processedFile = new File([blob], 'image.png', {
            type: blob.type,
          });
          this.currentFile = processedFile;
          this.cropperReady = true;
          this.isLoading = false;
          this.cdr.detectChanges();
        }
      });
    }
  }

  /**
   * Handles upload error event.
   * @param event The upload error event.
   */
  onUploadError(): void {
    const errorMessage =
      "Error uploading file. Please ensure it's an image under 5MB.";
    this.errorMessage = errorMessage;
    this.uploadError.emit(errorMessage);
  }

  /**
   * Handles image cropped event.
   * @param event The image cropped event.
   */
  onImageCropped(event: ImageCroppedEvent): void {
    // Revoke the previous object URL to prevent memory leak
    this.revokeCroppedImageUrl();

    this.croppedImageUrl = isDefined(event.objectUrl) ? event.objectUrl : null;

    if (isDefined(event)) {
      this.imageCropped.emit(event);
    }
  }

  /**
   * Handles image loaded event.
   * @param event The image loaded event.
   */
  onImageLoaded(): void {
    this.isLoading = false;
    this.errorMessage = null;
    this.transform = { scale: 1 };
    this.canvasRotation = 0;
    this.imageLoaded.emit();
  }

  /**
   * Handles load error event.
   * @param event The load error event.
   */
  onLoadError(): void {
    const errorMessage = 'Error loading image. Please try another file.';
    this.isLoading = false;
    this.errorMessage = errorMessage;
    this.loadError.emit(errorMessage);
    this.resetImage();
  }

  /**
   * Handles zoom change event.
   */
  onZoomChange(): void {
    this.cropper.transform = { ...this.transform };
  }

  /**
   * Rotates the image to the left.
   */
  rotateLeft(): void {
    this.canvasRotation--;
    this.flipAfterRotate();
  }

  /**
   * Rotates the image to the right.
   */
  rotateRight(): void {
    this.canvasRotation++;
    this.flipAfterRotate();
  }

  /**
   * Flips the image after rotation.
   */
  private flipAfterRotate(): void {
    const flippedH = this.transform.flipH;
    const flippedV = this.transform.flipV;
    this.transform = {
      ...this.transform,
      flipH: flippedV,
      flipV: flippedH,
    };
  }

  /**
   * Resets the image editor state.
   */
  resetImage(): void {
    // Revoke object URL before resetting to prevent memory leak
    this.revokeCroppedImageUrl();

    this.currentFile = null;
    this.croppedImageUrl = null;
    this.errorMessage = null;
    this.transform = { scale: 1 };
    this.canvasRotation = 0;
    this.isImageRemoved = true;
  }

  /**
   * Crops and saves the image.
   */
  async cropAndSave(): Promise<void> {
    if (isDefined(this.croppedImageUrl)) {
      this.isLoading = true;
      try {
        const response = await fetch(this.croppedImageUrl);
        const blob = await response.blob();
        const fileName = isDefined(this.currentFile?.name)
          ? this.currentFile?.name
          : 'cropped-image.png';
        const croppedFile = new File([blob], fileName, { type: blob.type });
        this.croppedFile.emit(croppedFile);
        this.resetAndClose();
      } catch (error: unknown) {
        const errorMessage = 'Error saving cropped image. Please try again.';
        this.errorMessage = errorMessage;
        this.loadError.emit(errorMessage);
        throw error;
      } finally {
        this.isLoading = false;
      }
    } else if (this.saveOnEmpty()) {
      this.imageRemoved.emit();
      this.resetImage();
    }
  }

  /**
   * Handles modal close event.
   */
  onClose(): void {
    this.resetAndClose();
  }

  /**
   * Resets the image editor state and closes the modal.
   */
  private resetAndClose(): void {
    this.visibleChange.emit(false);
    this.resetImage();
  }

  /**
   * Handles file upload choose event.
   * @param event The file selection event
   * @param callback The callback function to execute after file selection
   */
  choose(_event: MouseEvent, callback: () => void): void {
    callback();
  }

  /**
   * Triggers the hidden file input dialog
   */
  triggerFileInput(): void {
    this.fileInput.nativeElement.click();
  }

  /**
   * Handles file selection from the simple file input
   * @param event The file input change event
   */
  onFileInputChange(event: Event): void {
    const input = event.target as HTMLInputElement;
    if (input.files && input.files.length > 0) {
      const file = input.files[0];
      this.errorMessage = null;
      this.cropperReady = false;
      this.fileSelected.emit(file);
      this.processOriginal(file);
      // Reset the input so the same file can be selected again if needed
      input.value = '';
    }
  }

  /**
   * Revokes the current cropped image URL to free up memory
   */
  private revokeCroppedImageUrl(): void {
    if (isDefined(this.croppedImageUrl)) {
      URL.revokeObjectURL(this.croppedImageUrl);
    }
  }

  /**
   * Cleanup when component is destroyed
   */
  ngOnDestroy(): void {
    this.revokeCroppedImageUrl();
  }
}
